export class StAstReflection extends AbstractAstReflection {
    getAllTypes(): string[] {
        return [
            'Action_call_statement',
            'Alias',
            'Arr_string',
            'Array_element',
            'Array_liters',
            'AssignPrefix',
            'Assignment_subrule',
            'Case_element',
            'Case_list',
            'Case_list_element',
            'Case_statement',
            'ComposeElement',
            'Constant',
            'Enum',
            'Expression',
            'For_list',
            'For_statement',
            'FunctionBlock',
            'FunctionExpression',
            'Function_invoke_or_assign',
            'Function_invoke_or_assign_statement',
            'If_statement',
            'InputsList',
            'InputsListSingle',
            'Interface',
            'Invoke_subrule',
            'Iteration_statement',
            'MemberCall',
            'Methods',
            'NamedElement',
            'Native_Type_Name',
            'Param_assignment',
            'PrimaryVariable',
            'Program',
            'RefFunctionOrBlockName',
            'Repeat_statement',
            'ReqParams',
            'ReturnParse',
            'Selection_statement',
            'St',
            'StEnum',
            'StFunction',
            'Statement',
            'Statement_list',
            'Statement_list_single',
            'Struct_Var_Decl_Init',
            'StructsList',
            'Subscript_list',
            'UnionsList',
            'Universe',
            'VarDeclarationInit',
            'VarInput',
            'VarLocal',
            'VarOutput',
            'VariableExpression',
            'While_statement'
        ];
    }

    protected override computeIsSubtype(subtype: string, supertype: string): boolean {
        switch (subtype) {
            case Array_liters: {
                return this.isSubtype(Native_Type_Name, supertype);
            }
            case Constant:
            case FunctionExpression:
            case MemberCall:
            case VariableExpression: {
                return this.isSubtype(Expression, supertype);
            }
            case Expression: {
                return this.isSubtype(Subscript_list, supertype);
            }
            case Function_invoke_or_assign_statement:
            case Iteration_statement:
            case Selection_statement: {
                return this.isSubtype(Statement, supertype);
            }
            case FunctionBlock:
            case StructsList: {
                return this.isSubtype(ComposeElement, supertype);
            }
            case NamedElement: {
                return this.isSubtype(Universe, supertype);
            }
            case StFunction: {
                return this.isSubtype(ComposeElement, supertype) || this.isSubtype(Universe, supertype);
            }
            case Struct_Var_Decl_Init:
            case VarDeclarationInit: {
                return this.isSubtype(NamedElement, supertype);
            }
            default: {
                return false;
            }
        }
    }

    getReferenceType(refInfo: ReferenceInfo): string {
        const referenceId = `${refInfo.container.$type}:${refInfo.property}`;
        switch (referenceId) {
            case 'Action_call_statement:actionName':
            case 'AssignPrefix:varEnchanceDecl':
            case 'RefFunctionOrBlockName:refFunctionName': {
                return Universe;
            }
            case 'Array_liters:Identifier':
            case 'Native_Type_Name:Identifier': {
                return ComposeElement;
            }
            case 'For_statement:controlVariable':
            case 'MemberCall:element':
            case 'VariableExpression:variable': {
                return NamedElement;
            }
            case 'Interface:extender': {
                return Interface;
            }
            default: {
                throw new Error(`${referenceId} is not a valid reference id.`);
            }
        }
    }

    getTypeMetaData(type: string): TypeMetaData {
        switch (type) {
            case 'Action_call_statement': {
                return {
                    name: 'Action_call_statement',
                    properties: [{ name: 'actionName' }]
                };
            }
            case 'Alias': {
                return {
                    name: 'Alias',
                    properties: [{ name: 'aliasName' }, { name: 'refName' }]
                };
            }
            case 'Arr_string': {
                return {
                    name: 'Arr_string',
                    properties: [{ name: 'arrElements', defaultValue: [] }]
                };
            }
            case 'Array_element': {
                return {
                    name: 'Array_element',
                    properties: [{ name: 'left' }, { name: 'right' }]
                };
            }
            case 'Assignment_subrule': {
                return {
                    name: 'Assignment_subrule',
                    properties: [{ name: 'expression' }]
                };
            }
            case 'AssignPrefix': {
                return {
                    name: 'AssignPrefix',
                    properties: [{ name: 'varEnchanceDecl' }]
                };
            }
            case 'Case_element': {
                return {
                    name: 'Case_element',
                    properties: [{ name: 'caseList' }, { name: 'statements' }]
                };
            }
            case 'Case_list': {
                return {
                    name: 'Case_list',
                    properties: [{ name: 'caseListElement', defaultValue: [] }]
                };
            }
            case 'Case_list_element': {
                return {
                    name: 'Case_list_element',
                    properties: [{ name: 'enumCase' }, { name: 'numCaseStart' }, { name: 'numericCaseEnd' }]
                };
            }
            case 'Case_statement': {
                return {
                    name: 'Case_statement',
                    properties: [{ name: 'caseElements', defaultValue: [] }, { name: 'caseExpression' }, { name: 'elseStatements' }]
                };
            }
            case 'Enum': {
                return {
                    name: 'Enum',
                    properties: [{ name: 'assignValue' }, { name: 'variable_name' }]
                };
            }
            case 'Expression': {
                return {
                    name: 'Expression',
                    properties: [{ name: 'left' }, { name: 'operator' }, { name: 'prior' }, { name: 'right' }, { name: 'value' }]
                };
            }
            case 'For_list': {
                return {
                    name: 'For_list',
                    properties: [{ name: 'byExpr' }, { name: 'forExpr' }, { name: 'toExpr' }]
                };
            }
            case 'For_statement': {
                return {
                    name: 'For_statement',
                    properties: [{ name: 'controlVariable' }, { name: 'forList' }, { name: 'statementList' }]
                };
            }
            case 'Function_invoke_or_assign': {
                return {
                    name: 'Function_invoke_or_assign',
                    properties: [{ name: 'assign' }, { name: 'assignPrefix' }, { name: 'id' }, { name: 'params', defaultValue: [] }]
                };
            }
            case 'Function_invoke_or_assign_statement': {
                return {
                    name: 'Function_invoke_or_assign_statement',
                    properties: [{ name: 'statement' }]
                };
            }
            case 'FunctionBlock': {
                return {
                    name: 'FunctionBlock',
                    properties: [
                        { name: 'methods', defaultValue: [] },
                        { name: 'name' },
                        { name: 'statementList', defaultValue: [] },
                        { name: 'varInputs', defaultValue: [] },
                        { name: 'varLocals', defaultValue: [] },
                        { name: 'varOutputs', defaultValue: [] }
                    ]
                };
            }
            case 'If_statement': {
                return {
                    name: 'If_statement',
                    properties: [
                        { name: 'elseStatement' },
                        { name: 'elsifConditions', defaultValue: [] },
                        { name: 'elsifStatements' },
                        { name: 'ifCondition' },
                        { name: 'ifStatement' }
                    ]
                };
            }
            case 'InputsList': {
                return {
                    name: 'InputsList',
                    properties: [{ name: 'definition' }, { name: 'items', defaultValue: [] }, { name: 'modifiers' }]
                };
            }
            case 'InputsListSingle': {
                return {
                    name: 'InputsListSingle',
                    properties: [{ name: 'definition' }, { name: 'items', defaultValue: [] }, { name: 'modifiers' }]
                };
            }
            case 'Interface': {
                return {
                    name: 'Interface',
                    properties: [{ name: 'extender' }, { name: 'methods', defaultValue: [] }, { name: 'name' }]
                };
            }
            case 'Invoke_subrule': {
                return {
                    name: 'Invoke_subrule',
                    properties: [{ name: 'parameters', defaultValue: [] }]
                };
            }
            case 'Iteration_statement': {
                return {
                    name: 'Iteration_statement',
                    properties: [{ name: 'statement' }]
                };
            }
            case 'Methods': {
                return {
                    name: 'Methods',
                    properties: [
                        { name: 'inputs', defaultValue: [] },
                        { name: 'modifier' },
                        { name: 'name' },
                        { name: 'reqParams', defaultValue: [] },
                        { name: 'statementList' },
                        { name: 'variable_type' }
                    ]
                };
            }
            case 'Native_Type_Name': {
                return {
                    name: 'Native_Type_Name',
                    properties: [
                        { name: 'Bit_string_type_name' },
                        { name: 'Bool_type_name' },
                        { name: 'Cache_type_name' },
                        { name: 'Date_And_time_type_name' },
                        { name: 'Date_type_name' },
                        { name: 'Identifier' },
                        { name: 'Integer_type_name' },
                        { name: 'Real_type_name' },
                        { name: 'String_type_name' },
                        { name: 'Time_Of_Day_type_name' },
                        { name: 'Time_type_name' },
                        { name: 'Unsigned_integer_type_name' }
                    ]
                };
            }
            case 'Param_assignment': {
                return {
                    name: 'Param_assignment',
                    properties: [{ name: 'InputOrOutputSign' }, { name: 'ParamName' }, { name: 'ParamValue' }]
                };
            }
            case 'PrimaryVariable': {
                return {
                    name: 'PrimaryVariable',
                    properties: [{ name: 'name' }]
                };
            }
            case 'Program': {
                return {
                    name: 'Program',
                    properties: [{ name: 'inputs', defaultValue: [] }, { name: 'name' }, { name: 'stStatements' }]
                };
            }
            case 'RefFunctionOrBlockName': {
                return {
                    name: 'RefFunctionOrBlockName',
                    properties: [{ name: 'Cache_type_name' }, { name: 'refFunctionName' }]
                };
            }
            case 'Repeat_statement': {
                return {
                    name: 'Repeat_statement',
                    properties: [{ name: 'statementList' }, { name: 'untilExpr' }]
                };
            }
            case 'ReqParams': {
                return {
                    name: 'ReqParams',
                    properties: [{ name: 'param' }, { name: 'typeName' }]
                };
            }
            case 'ReturnParse': {
                return {
                    name: 'ReturnParse',
                    properties: [{ name: 'returnSign' }, { name: 'returnValue' }]
                };
            }
            case 'Selection_statement': {
                return {
                    name: 'Selection_statement',
                    properties: [{ name: 'case' }, { name: 'if' }]
                };
            }
            case 'St': {
                return {
                    name: 'St',
                    properties: [
                        { name: 'function_block', defaultValue: [] },
                        { name: 'itface', defaultValue: [] },
                        { name: 'program', defaultValue: [] },
                        { name: 'st_function', defaultValue: [] },
                        { name: 'types_alias', defaultValue: [] },
                        { name: 'types_enum', defaultValue: [] },
                        { name: 'types_struct', defaultValue: [] },
                        { name: 'types_union', defaultValue: [] }
                    ]
                };
            }
            case 'Statement_list': {
                return {
                    name: 'Statement_list',
                    properties: [{ name: 'statements', defaultValue: [] }]
                };
            }
            case 'Statement_list_single': {
                return {
                    name: 'Statement_list_single',
                    properties: [{ name: 'statements' }]
                };
            }
            case 'StEnum': {
                return {
                    name: 'StEnum',
                    properties: [{ name: 'enum', defaultValue: [] }, { name: 'name' }]
                };
            }
            case 'StFunction': {
                return {
                    name: 'StFunction',
                    properties: [
                        { name: 'name' },
                        { name: 'statementList', defaultValue: [] },
                        { name: 'variable_type' },
                        { name: 'varInputs', defaultValue: [] },
                        { name: 'varLocals', defaultValue: [] },
                        { name: 'varOutputs', defaultValue: [] }
                    ]
                };
            }
            case 'Struct_Var_Decl_Init': {
                return {
                    name: 'Struct_Var_Decl_Init',
                    properties: [
                        { name: 'initialValue' },
                        { name: 'nextVariables', defaultValue: [] },
                        { name: 'typeName' },
                        { name: 'variables' }
                    ]
                };
            }
            case 'StructsList': {
                return {
                    name: 'StructsList',
                    properties: [{ name: 'items', defaultValue: [] }, { name: 'name' }]
                };
            }
            case 'UnionsList': {
                return {
                    name: 'UnionsList',
                    properties: [{ name: 'items', defaultValue: [] }, { name: 'name' }]
                };
            }
            case 'VarDeclarationInit': {
                return {
                    name: 'VarDeclarationInit',
                    properties: [
                        { name: 'initialValue' },
                        { name: 'nextVariables', defaultValue: [] },
                        { name: 'typeName' },
                        { name: 'variables' }
                    ]
                };
            }
            case 'VarInput': {
                return {
                    name: 'VarInput',
                    properties: [{ name: 'items', defaultValue: [] }]
                };
            }
            case 'VarLocal': {
                return {
                    name: 'VarLocal',
                    properties: [{ name: 'items', defaultValue: [] }]
                };
            }
            case 'VarOutput': {
                return {
                    name: 'VarOutput',
                    properties: [{ name: 'items', defaultValue: [] }]
                };
            }
            case 'While_statement': {
                return {
                    name: 'While_statement',
                    properties: [{ name: 'statementList' }, { name: 'whileExpr' }]
                };
            }
            case 'Constant': {
                return {
                    name: 'Constant',
                    properties: [
                        { name: 'constant' },
                        { name: 'left' },
                        { name: 'operator' },
                        { name: 'prior' },
                        { name: 'right' },
                        { name: 'value' }
                    ]
                };
            }
            case 'FunctionExpression': {
                return {
                    name: 'FunctionExpression',
                    properties: [
                        { name: 'left' },
                        { name: 'operator' },
                        { name: 'params' },
                        { name: 'prefixValidateElement' },
                        { name: 'prior' },
                        { name: 'refFunctionName' },
                        { name: 'right' },
                        { name: 'suffixValidateElement' },
                        { name: 'value' }
                    ]
                };
            }
            case 'MemberCall': {
                return {
                    name: 'MemberCall',
                    properties: [
                        { name: 'arguments', defaultValue: [] },
                        { name: 'element' },
                        { name: 'explicitOperationCall', defaultValue: false },
                        { name: 'left' },
                        { name: 'operator' },
                        { name: 'previous' },
                        { name: 'prior' },
                        { name: 'right' },
                        { name: 'value' }
                    ]
                };
            }
            case 'VariableExpression': {
                return {
                    name: 'VariableExpression',
                    properties: [
                        { name: 'left' },
                        { name: 'operator' },
                        { name: 'prior' },
                        { name: 'right' },
                        { name: 'value' },
                        { name: 'variable' }
                    ]
                };
            }
            case 'Array_liters': {
                return {
                    name: 'Array_liters',
                    properties: [
                        { name: 'arrayElemets', defaultValue: [] },
                        { name: 'Bit_string_type_name' },
                        { name: 'Bool_type_name' },
                        { name: 'Cache_type_name' },
                        { name: 'dataType' },
                        { name: 'Date_And_time_type_name' },
                        { name: 'Date_type_name' },
                        { name: 'Identifier' },
                        { name: 'Integer_type_name' },
                        { name: 'Real_type_name' },
                        { name: 'String_type_name' },
                        { name: 'Time_Of_Day_type_name' },
                        { name: 'Time_type_name' },
                        { name: 'Unsigned_integer_type_name' }
                    ]
                };
            }
            default: {
                return {
                    name: type,
                    properties: []
                };
            }
        }
    }
}

export const reflection = new StAstReflection();
